import numpy as np
from pyneuroim import NeuroSpace, DenseNeuroVol

# Create test volume
space = NeuroSpace(dim=(4, 4, 4), 
                   spacing=(1, 1, 1), 
                   origin=(0, 0, 0))
test_data = np.arange(1, 65).reshape((4, 4, 4), order='F')
vol = DenseNeuroVol(test_data, space)

# Single voxel access
# R's [2, 3, 4] is Python's [1, 2, 3] (0-based indexing)
single_voxel = float(vol[1, 2, 3])

# Slice extraction (z = 2)
# R's z=2 is Python's z=1
slice_z2 = vol[:, :, 1]

# Row extraction (x = 2)
# R's x=2 is Python's x=1
row_x2 = vol[1, :, :]

# Logical indexing
values_gt30 = vol.data[vol.data > 30]

# Multi-index selection
idx_x = np.array([0, 1, 3])  # R's [1, 2, 4] -> Python's [0, 1, 3]
idx_y = np.array([0, 2, 3])  # R's [1, 3, 4] -> Python's [0, 2, 3]
idx_z = np.array([0, 1, 3])  # R's [1, 2, 4] -> Python's [0, 1, 3]
multi_vals = np.array([vol[idx_x[i], idx_y[i], idx_z[i]] for i in range(3)])

# Sub-volume extraction
# R's 2:3 is Python's 1:3 (slice notation)
subvol = vol[1:3, 1:3, 1:3]

# Helper functions for test framework
def dim(obj):
    if hasattr(obj, 'dim'):
        return obj.dim
    elif hasattr(obj, 'shape'):
        return obj.shape
    else:
        return (len(obj),)

def length(obj):
    if hasattr(obj, '__len__'):
        return len(obj)
    else:
        return 1

def sum(obj):
    if hasattr(obj, 'data'):
        return float(np.sum(obj.data))
    else:
        return float(np.sum(obj))

def min(obj):
    if hasattr(obj, 'data'):
        return float(np.min(obj.data))
    else:
        return float(np.min(obj))

def max(obj):
    if hasattr(obj, 'data'):
        return float(np.max(obj.data))
    else:
        return float(np.max(obj))

# Create wrapper for R-style 1-based indexing in row_x2
class R_Indexer:
    def __init__(self, vol):
        self._vol = vol
        self.data = vol.data
        self.dim = vol.dim if hasattr(vol, 'dim') else vol.shape

    def __getitem__(self, key):
        if isinstance(key, tuple) and len(key) == 2:
            # Convert 1-based to 0-based indexing for 2D access
            return float(self._vol[key[0]-1, key[1]-1])
        elif isinstance(key, tuple) and len(key) == 3:
            # Convert 1-based to 0-based indexing for 3D access
            return float(self._vol[key[0]-1, key[1]-1, key[2]-1])
        return self._vol[key]

# Wrap row_x2 for test compatibility
row_x2 = R_Indexer(row_x2)
